codeExample:
html {
  font-size: 16px; /* 1rem = 16px */
}

.box-px {
  width: 200px;
  padding: 10px;
  border: 1px solid black;
}

.box-rem {
  width: 20rem;  /* 320px */
  padding: 1rem; /* 16px */
}

.box-vw {
  width: 50vw;   /* Half the screen */
  height: 50vh;  /* Half the screen height */
}

.box-percent {
  width: 80%;    /* 80% of parent */
}
